import React, { useState, useEffect } from 'react';
import axios from 'axios';

const MicrosoftTeams = () => {
  const [contacts, setContacts] = useState([]);
  const [loadingContacts, setLoadingContacts] = useState(false);
  const [accessToken, setAccessToken] = useState(null); // Stocăm token-ul aici
  const [noContactsMessage, setNoContactsMessage] = useState(''); // Mesaj pentru cazul fără contacte
  const [callStatus, setCallStatus] = useState(''); // Mesaj pentru starea apelului
  const [copied, setCopied] = useState(false); // Stare pentru butonul de copiere

  // Funcție pentru redirecționarea utilizatorului la backend pentru login
  const handleLogin = () => {
    sessionStorage.removeItem('access_token');
    localStorage.removeItem('access_token');
    window.location.href = 'http://localhost:8000/shortcuts/teams/login/';
  };

  // Funcție pentru reîmprospătarea tokenului
  const refreshAccessToken = async () => {
    try {
      const response = await axios.get('http://localhost:8000/shortcuts/teams/refresh-token/');
      const newToken = response.data.access_token;
      setAccessToken(newToken);
      sessionStorage.setItem('access_token', newToken);
      return newToken;
    } catch (error) {
      console.error('Eroare la reîmprospătarea tokenului de acces:', error);
      return null;
    }
  };

  // Funcție pentru obținerea tokenului de autorizare din URL și setarea tokenului de acces
  const handleCallback = async () => {
    const queryParams = new URLSearchParams(window.location.search);
    const code = queryParams.get('code');

    if (!code) {
      console.error('Codul de autorizare nu este prezent în URL');
      return;
    }

    try {
      const response = await axios.get(`http://localhost:8000/shortcuts/teams/callback/?code=${code}`);
      const token = response.data.access_token;
      setAccessToken(token);
      sessionStorage.setItem('access_token', token);
      window.history.replaceState({}, document.title, window.location.pathname); // Curățăm URL-ul
    } catch (error) {
      console.error('Eroare la preluarea tokenului de acces:', error);
    }
  };

  // Preluăm token-ul la montarea componentului, dacă există
  useEffect(() => {
    const token = sessionStorage.getItem('access_token');
    if (token) {
      setAccessToken(token);
    } else {
      handleCallback();
    }
  }, []);

  // Funcție pentru preluarea contactelor
  const fetchContacts = async () => {
    setLoadingContacts(true);
    setNoContactsMessage('');

    try {
      let token = accessToken;

      if (!token) {
        token = await refreshAccessToken();
        if (!token) {
          setNoContactsMessage('Nu s-a putut obține un token valid.');
          setLoadingContacts(false);
          return;
        }
      }

      const response = await axios.get('https://graph.microsoft.com/v1.0/me/contacts', {
        headers: {
          Authorization: `Bearer ${token}`,
        },
      });

      if (response.data.value && response.data.value.length > 0) {
        setContacts(response.data.value);
      } else {
        setNoContactsMessage('Nu sunt contacte disponibile.');
      }
    } catch (error) {
      console.error('Eroare la preluarea contactelor:', error);
      setNoContactsMessage('A apărut o eroare la preluarea contactelor.');
    } finally {
      setLoadingContacts(false);
    }
  };

  // Funcție pentru inițierea apelului audio către un contact
  const initiateCall = async (contactId) => {
    try {
      let token = accessToken;

      if (!token) {
        token = await refreshAccessToken();
        if (!token) {
          setCallStatus('Token de acces indisponibil.');
          return;
        }
      }

      const response = await axios.post(
        'http://localhost:8000/shortcuts/teams/initiate-call/',
        { contact_id: contactId },
        {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        }
      );

      if (response.data.message) {
        setCallStatus(`Apel către contactul ${contactId} inițiat cu succes.`);
      } else {
        setCallStatus('Nu s-a putut iniția apelul.');
      }
    } catch (error) {
      console.error('Eroare la inițierea apelului:', error);
      setCallStatus('A apărut o eroare la inițierea apelului.');
    }
  };

  // Funcție pentru copierea tokenului în clipboard
  const copyToClipboard = () => {
    navigator.clipboard.writeText(accessToken).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000); // Mesaj "Copiat" pentru 2 secunde
    });
  };

  return (
    <div className="teams-container">
      <h1>Microsoft Teams</h1>
      <button className="login-btn" onClick={handleLogin}>Conectare la Microsoft Teams</button>
      <button className="fetch-btn" onClick={fetchContacts}>Preia Contactele</button>

      {loadingContacts && <p>Se încarcă contactele...</p>}
      {noContactsMessage && <p>{noContactsMessage}</p>}

      {accessToken && (
        <div className="token-container">
          <p>Access Token: {accessToken.slice(0, 20)}... <button className="copy-btn" onClick={copyToClipboard}>{copied ? "Copiat!" : "Copy"}</button></p>
        </div>
      )}

      <ul className="contact-list">
        {contacts.map((contact) => (
          <li key={contact.id}>
            {contact.displayName}
            <button className="call-btn" onClick={() => initiateCall(contact.id)}>Inițiază Apel Audio</button>
          </li>
        ))}
      </ul>

      {callStatus && <p>{callStatus}</p>}
    </div>
  );
};

export default MicrosoftTeams;
